const uint32_t DOOM_FRAME_COUNT = 50U;
const uint32_t DOOM_FPS        = 5U;

void DoomFrames_Blit(uint32_t idx)
{
    const uint8_t *src = frame_data + frame_offsets[idx];
    const uint8_t *end = src + frame_lengths[idx];
    uint8_t *fb = OLED_Framebuffer();
    /* Data is column-major: col 0 pages 0-7, col 1 pages 0-7, ... */
    /* Rearrange into page-major fb layout: fb[page*128 + col].     */
    uint8_t col = 0u, page = 0u;
    while (src < end) {
        uint8_t count = *src++;
        uint8_t value = *src++;
        do {
            fb[(uint16_t)page * 128u + col] = value;
            if (++page == 8u) { page = 0u; ++col; }
        } while (--count);
    }
}
